from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True,
        dtd_validation=False,
        load_dtd=False
    )

    try:
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    expr = "//student[username=$user and password=$pass]"
    students = root.xpath(expr, **{'user': username, 'pass': password})

    if not students:
        return None

    student = students[0]
    info = {}
    for child in student:
        info[child.tag] = child.text if child.text is not None else ""

    return info

