import subprocess
import shlex

ALLOWED_COMMANDS = {'ls', 'pwd', 'echo', 'date'}

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    user_input = input("Enter command: ")

    # Validate that the input is not empty
    if not user_input.strip():
        print("Empty command")
        return

    try:
        # Safely split the command into arguments
        args = shlex.split(user_input)
        if not args:
            print("Invalid command")
            return

        # Validate command against an allowlist to prevent execution of untrusted input (CWE-78)
        if args[0] not in ALLOWED_COMMANDS:
            print("Command not allowed")
            return

        # Execute the command without shell=True to prevent command injection (CWE-78)
        result = subprocess.run(args, shell=False, capture_output=True, text=True)

        if result.stdout:
            print(result.stdout, end='')
        if result.stderr:
            print(result.stderr, end='')

    except FileNotFoundError:
        print("Command not found")
    except Exception as e:
        print(f"Error executing command: {e}")

