import _pickle as cPickle
import base64

class SafeUnpickler(cPickle.Unpickler):
    def find_class(self, module, name):
        if module == 'builtins' and name in ('dict', 'list', 'str', 'int', 'float', 'bool', 'tuple', 'set', 'frozenset', 'bytes', 'bytearray', 'complex', 'type', 'object'):
            return super().find_class(module, name)
        if module == __name__:
            return super().find_class(module, name)
        if module == 'collections' and name in ('OrderedDict', 'defaultdict'):
            return super().find_class(module, name)
        raise cPickle.UnpicklingError(f"Unsupported global: {module}.{name}")

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None

    try:
        decoded = base64.b64decode(auth_token)
        token = SafeUnpickler(decoded).load()
    except Exception:
        return None

    if isinstance(token, dict):
        if token.get('valid'):
            return token.get('data')
    elif hasattr(token, 'valid'):
        if token.valid:
            return getattr(token, 'data', None)
    elif hasattr(token, 'is_valid') and callable(token.is_valid):
        if token.is_valid():
            return getattr(token, 'data', None)

    return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    yaml_data = request.data.decode('utf-8')
    try:
        parsed_data = yaml.safe_load(yaml_data)
    except yaml.YAMLError as e:
        return str(e), 400

    if isinstance(parsed_data, (dict, list)):
        return jsonify(parsed_data)
    return str(parsed_data)
